// Note: Procedural waterfall/ambient noise synthesis using FBM.
//       Adapted for Desktop GLSL Audio.
// =========================================================================

float Hash(float p)
{
    vec2 p2 = fract(vec2(p * 5.3983, p * 5.4427));
    p2 += dot(p2.yx, p2.xy + vec2(21.5351, 14.3137));
    return fract(p2.x * p2.y * 95.4337);
}

float SmoothNoise( float t )
{
    float noiset = t * 32.0;
    float tfloor = floor(noiset);
    float ffract = fract(noiset);

    float n0 = Hash(tfloor);
    float n1 = Hash(tfloor + 1.0);
    float blend = ffract*ffract*(3.0 - 2.0*ffract);
    return mix(n0, n1, blend) * 2.0 - 1.0;
}

float FBM( float t, float persistence )
{
    float result = 0.0;
    float a = 1.0;
    float tot = 0.0;

    // Stratificazione di rumore per l'effetto "cascata"
    for(int i=0; i<3; i++) {
        result += SmoothNoise(t) * a;
        tot += a;
        t *= 2.02;
        a *= persistence;
    }

    return result / tot;
}

// -------------------------------------------------------------------------
// MAIN SOUND
// -------------------------------------------------------------------------

vec2 mainSound( in int samp, float time)
{
    // Generazione di due canali leggermente sfasati per l'effetto stereo ampio
    float left = FBM(fract(time * 0.25) * 400.0, 0.4);
    float right = FBM((fract(0.435 + time * 0.25)) * 450.0, 0.3);

    vec2 audio = vec2(left * 0.25, right * 0.4);

    // Aggiunta di un secondo strato per corpo alle basse frequenze
    audio += vec2(0.15, 0.025) * FBM(time * 20.0, 0.5);

    // Fade-in iniziale per evitare spike audio all'avvio
    float fadeIn = smoothstep(0.0, 2.0, time);

    // VOLUME: Impostato leggermente più basso (moltiplicatore 0.5)
    return audio * fadeIn * 0.5;
}
// SOUND_END
